// ── Sucesso: todos os serviços resetados para RUN_STATUS = 0 ──
const allRows = $input.all();
const resetted = allRows.map(item => item.json);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'clean_up',
  event: 'all_services_reset',
  total_resetted: resetted.length,
  services: resetted.map(r => r.ACTION),
  level: 'info'
}));

return {
  statusCode: 201,
  body: { message: 'Update extension service status' }
};

// ── Erro do Postgres durante o reset ──
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'clean_up',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not reset extension services status' }
};
